import { ipcMain } from 'electron';
import {
  IPC_CHANNELS,
  ServerIdSchema,
  Fail2BanConfigSchema,
  Fail2BanUnbanSchema,
  Fail2BanWhitelistSchema,
  UFWRuleSchema,
  UFWDeleteRuleSchema,
  UFWSetDefaultSchema,
  SSHConfigSchema,
  SSHPortChangeSchema,
  SSHTestUsernameSchema,
  AutoUpdatesConfigSchema,
  SecurityAuditSchema,
  UserListSchema,
  UserCreateSchema,
  UserDeleteSchema,
  UserAddKeySchema,
  UserListKeysSchema,
  UserRemoveKeySchema,
  ApiResult,
  Fail2BanStatus,
  UFWStatus,
  SSHStatus,
  AutoUpdatesStatus,
  SecurityAuditResult,
  SSHPortChangeResult,
  UserInfo,
  UserSSHKey,
  CreateUserResult,
} from './types';
import { securityService } from '../services/SecurityService';
import { sshService } from '../services/SSHService';
import { CredentialVault } from '../services/CredentialVault';
import { queries } from '../db';

export function registerSecurityHandlers() {
  // ============ fail2ban Handlers ============

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_FAIL2BAN_STATUS,
    async (_event, input): Promise<ApiResult<Fail2BanStatus>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        const status = await securityService.getFail2BanStatus(serverId);
        return { success: true, data: status };
      } catch (error) {
        console.error('Error getting fail2ban status:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_FAIL2BAN_INSTALL,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        await securityService.installFail2Ban(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error installing fail2ban:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_FAIL2BAN_CONFIGURE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const config = Fail2BanConfigSchema.parse(input);
        await securityService.configureFail2Ban(config.serverId, config);
        return { success: true };
      } catch (error) {
        console.error('Error configuring fail2ban:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_FAIL2BAN_UNBAN,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, ip, jail } = Fail2BanUnbanSchema.parse(input);
        await securityService.unbanIP(serverId, ip, jail);
        return { success: true };
      } catch (error) {
        console.error('Error unbanning IP:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_FAIL2BAN_WHITELIST,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, ips } = Fail2BanWhitelistSchema.parse(input);
        // Get current config and update whitelist
        const status = await securityService.getFail2BanStatus(serverId);
        if (status.config) {
          await securityService.configureFail2Ban(serverId, {
            serverId,
            enabled: status.sshJail.enabled,
            banTime: status.config.banTime,
            findTime: status.config.findTime,
            maxRetry: status.config.maxRetry,
            whitelistIPs: ips,
          });
        }
        return { success: true };
      } catch (error) {
        console.error('Error updating whitelist:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ UFW Firewall Handlers ============

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UFW_STATUS,
    async (_event, input): Promise<ApiResult<UFWStatus>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        const status = await securityService.getUFWStatus(serverId);
        return { success: true, data: status };
      } catch (error) {
        console.error('Error getting UFW status:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UFW_INSTALL,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        await securityService.installUFW(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error installing UFW:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UFW_ENABLE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        await securityService.enableUFW(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error enabling UFW:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UFW_DISABLE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        await securityService.disableUFW(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error disabling UFW:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UFW_ADD_RULE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const rule = UFWRuleSchema.parse(input);
        await securityService.addUFWRule(rule.serverId, {
          action: rule.action,
          port: rule.port,
          protocol: rule.protocol,
          from: rule.from,
          comment: rule.comment,
        });
        return { success: true };
      } catch (error) {
        console.error('Error adding UFW rule:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UFW_DELETE_RULE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, ruleNumber } = UFWDeleteRuleSchema.parse(input);
        await securityService.deleteUFWRule(serverId, ruleNumber);
        return { success: true };
      } catch (error) {
        console.error('Error deleting UFW rule:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UFW_SET_DEFAULT,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, direction, policy } = UFWSetDefaultSchema.parse(input);
        await securityService.setUFWDefault(serverId, direction, policy);
        return { success: true };
      } catch (error) {
        console.error('Error setting UFW default:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ SSH Hardening Handlers ============

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_SSH_STATUS,
    async (_event, input): Promise<ApiResult<SSHStatus>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        const status = await securityService.getSSHStatus(serverId);
        return { success: true, data: status };
      } catch (error) {
        console.error('Error getting SSH status:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_SSH_CONFIGURE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const config = SSHConfigSchema.parse(input);
        await securityService.configureSSH(config.serverId, config);
        return { success: true };
      } catch (error) {
        console.error('Error configuring SSH:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // Safe SSH port change with verification and database update
  ipcMain.handle(
    IPC_CHANNELS.SECURITY_SSH_CHANGE_PORT,
    async (_event, input): Promise<ApiResult<SSHPortChangeResult>> => {
      try {
        const { serverId, currentPort, newPort } = SSHPortChangeSchema.parse(input);

        const result = await securityService.changeSSHPortSafely(
          serverId,
          currentPort,
          newPort,
          (id, port) => {
            queries.updateServer(id, { port });
          }
        );

        return { success: true, data: result };
      } catch (error) {
        console.error('Error changing SSH port:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Auto Updates Handlers ============

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UPDATES_STATUS,
    async (_event, input): Promise<ApiResult<AutoUpdatesStatus>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        const status = await securityService.getAutoUpdatesStatus(serverId);
        return { success: true, data: status };
      } catch (error) {
        console.error('Error getting auto updates status:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UPDATES_INSTALL,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        await securityService.installAutoUpdates(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error installing auto updates:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UPDATES_CONFIGURE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const config = AutoUpdatesConfigSchema.parse(input);
        await securityService.configureAutoUpdates(config.serverId, config);
        return { success: true };
      } catch (error) {
        console.error('Error configuring auto updates:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UPDATES_CHECK,
    async (_event, input): Promise<ApiResult<{ pendingCount: number }>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        const pendingCount = await securityService.checkForUpdates(serverId);
        return { success: true, data: { pendingCount } };
      } catch (error) {
        console.error('Error checking for updates:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_UPDATES_APPLY,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        await securityService.applyUpdates(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error applying updates:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ Security Audit Handlers ============

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_AUDIT,
    async (_event, input): Promise<ApiResult<SecurityAuditResult>> => {
      try {
        const { serverId } = SecurityAuditSchema.parse(input);
        const result = await securityService.runSecurityAudit(serverId);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error running security audit:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_QUICK_HARDEN,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { id: serverId } = ServerIdSchema.parse(input);
        await securityService.quickHarden(serverId);
        return { success: true };
      } catch (error) {
        console.error('Error running quick harden:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // Test SSH connection with a different username (using existing server credentials)
  ipcMain.handle(
    IPC_CHANNELS.SECURITY_TEST_USERNAME,
    async (_event, input): Promise<ApiResult<boolean>> => {
      try {
        const { serverId, username } = SSHTestUsernameSchema.parse(input);

        // Get server info
        const server = queries.getServerById(serverId);
        if (!server) {
          return { success: false, error: 'Server not found' };
        }

        // Get decrypted credentials
        const vault = new CredentialVault();
        const credential = await vault.decrypt(server.encrypted_secret);

        // Build connection config with new username
        const connectionConfig: {
          host: string;
          port: number;
          username: string;
          password?: string;
          privateKey?: string;
        } = {
          host: server.host,
          port: server.port,
          username: username,
        };

        if (server.auth_type === 'password') {
          connectionConfig.password = credential;
        } else {
          connectionConfig.privateKey = credential;
        }

        // Test connection
        const result = await sshService.testConnection(connectionConfig);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error testing username:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  // ============ User Management Handlers ============

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_USERS_LIST,
    async (_event, input): Promise<ApiResult<UserInfo[]>> => {
      try {
        const { serverId } = UserListSchema.parse(input);
        const users = await securityService.listUsers(serverId);
        return { success: true, data: users };
      } catch (error) {
        console.error('Error listing users:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_USERS_CREATE,
    async (_event, input): Promise<ApiResult<CreateUserResult>> => {
      try {
        const params = UserCreateSchema.parse(input);
        const result = await securityService.createUser(params.serverId, params);
        return { success: true, data: result };
      } catch (error) {
        console.error('Error creating user:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_USERS_DELETE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, username, removeHome } = UserDeleteSchema.parse(input);
        await securityService.deleteUser(serverId, username, removeHome);
        return { success: true };
      } catch (error) {
        console.error('Error deleting user:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_USERS_ADD_KEY,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, username, publicKey } = UserAddKeySchema.parse(input);
        await securityService.addUserSSHKey(serverId, username, publicKey);
        return { success: true };
      } catch (error) {
        console.error('Error adding SSH key:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_USERS_LIST_KEYS,
    async (_event, input): Promise<ApiResult<UserSSHKey[]>> => {
      try {
        const { serverId, username } = UserListKeysSchema.parse(input);
        const keys = await securityService.listUserSSHKeys(serverId, username);
        return { success: true, data: keys };
      } catch (error) {
        console.error('Error listing SSH keys:', error);
        return { success: false, error: String(error) };
      }
    }
  );

  ipcMain.handle(
    IPC_CHANNELS.SECURITY_USERS_REMOVE_KEY,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, username, keyIndex } = UserRemoveKeySchema.parse(input);
        await securityService.removeUserSSHKey(serverId, username, keyIndex);
        return { success: true };
      } catch (error) {
        console.error('Error removing SSH key:', error);
        return { success: false, error: String(error) };
      }
    }
  );
}
